Sure! Here’s a simple test code for an ESP32 that connects to a Wi-Fi network and prints the IP address to the Serial Monitor:

```cpp
#include <WiFi.h>

const char* ssid = "your_SSID";     // Replace with your network SSID
const char* password = "your_PASSWORD"; // Replace with your network password

void setup() {
  Serial.begin(115200);
  WiFi.begin(ssid, password);

  while (WiFi.status() != WL_CONNECTED) {
    delay(1000);
    Serial.println("Connecting to WiFi...");
  }

  Serial.println("Connected to WiFi");
  Serial.print("IP Address: ");
  Serial.println(WiFi.localIP());
}

void loop() {
  // Your code here
}
```

Make sure to replace `"your_SSID"` and `"your_PASSWORD"` with your actual Wi-Fi credentials. Let me know if you need further explanations or adjustments!
